-- Patch 0031: Redesign model migration tables.
--
-- Replace the flat model_migration table (which mixed target credentials,
-- phase tracking and status into a single row) with a normalised schema:
--
--   model_migration_direction  -- lookup: export / import
--   model_migration_phase      -- lookup: mirrors core/migration/phase.go
--   model_migration            -- one row per migration attempt per side
--   model_migration_status     -- time-ordered phase/message history
--   model_migration_target     -- target controller (export side only)
--
-- The same migration uuid is generated by the source and propagated to the
-- target with the export payload, so both sides can be correlated.
DROP TABLE IF EXISTS model_migration_minion_sync;
DROP TABLE IF EXISTS model_migration_user;
DROP TABLE IF EXISTS model_migration_status;
DROP TABLE IF EXISTS model_migration;

CREATE TABLE model_migration_direction (
    id INT NOT NULL PRIMARY KEY,
    name TEXT NOT NULL
);

CREATE UNIQUE INDEX idx_model_migration_direction_name
ON model_migration_direction (name);

INSERT INTO model_migration_direction VALUES
(0, 'export'),
(1, 'import');

CREATE TABLE model_migration_phase (
    id INT NOT NULL PRIMARY KEY,
    name TEXT NOT NULL
);

CREATE UNIQUE INDEX idx_model_migration_phase_name
ON model_migration_phase (name);

INSERT INTO model_migration_phase VALUES
(0, 'UNKNOWN'),
(1, 'NONE'),
(2, 'QUIESCE'),
(3, 'IMPORT'),
(4, 'PROCESSRELATIONS'),
(5, 'VALIDATION'),
(6, 'SUCCESS'),
(7, 'LOGTRANSFER'),
(8, 'REAP'),
(9, 'REAPFAILED'),
(10, 'DONE'),
(11, 'ABORT'),
(12, 'ABORTDONE');

CREATE TABLE model_migration (
    uuid TEXT NOT NULL PRIMARY KEY,
    model_uuid TEXT NOT NULL,
    direction_id INT NOT NULL,
    attempt INT NOT NULL,
    start_time TIMESTAMP NOT NULL,
    CONSTRAINT fk_model_migration_model
    FOREIGN KEY (model_uuid)
    REFERENCES model (uuid),
    CONSTRAINT fk_model_migration_direction
    FOREIGN KEY (direction_id)
    REFERENCES model_migration_direction (id)
);

CREATE UNIQUE INDEX idx_model_migration_attempt
ON model_migration (model_uuid, direction_id, attempt);

CREATE TABLE model_migration_status (
    uuid TEXT NOT NULL PRIMARY KEY,
    migration_uuid TEXT NOT NULL,
    phase_id INT NOT NULL,
    message TEXT,
    changed_at TIMESTAMP NOT NULL,
    CONSTRAINT fk_model_migration_status_migration
    FOREIGN KEY (migration_uuid)
    REFERENCES model_migration (uuid),
    CONSTRAINT fk_model_migration_status_phase
    FOREIGN KEY (phase_id)
    REFERENCES model_migration_phase (id)
);

CREATE INDEX idx_model_migration_status_migration_changed_at
ON model_migration_status (migration_uuid, changed_at);

-- Only present for export-direction migrations. Enforcement that the linked
-- migration has direction_id = 0 ('export') is left to the service layer.
CREATE TABLE model_migration_target (
    migration_uuid TEXT NOT NULL PRIMARY KEY,
    external_controller_uuid TEXT NOT NULL,
    CONSTRAINT fk_model_migration_target_migration
    FOREIGN KEY (migration_uuid)
    REFERENCES model_migration (uuid),
    CONSTRAINT fk_model_migration_target_external_controller
    FOREIGN KEY (external_controller_uuid)
    REFERENCES external_controller (uuid)
);

CREATE INDEX idx_model_migration_target_external_controller
ON model_migration_target (external_controller_uuid);
